joi_block.script:
triggered := false
if ((#MultiButton).multiButton_button2 == "pushed") {
if (triggered == false) {
tmp = (#Light #Hallway).light_currentBrightness - 10
        if (tmp < 0) {
tmp = 0
}
(#Light #Hallway).light_moveToBrightness(tmp, 0)
        triggered = true
}
}
else {
triggered = false
}

